const validationData = $input.first().json;

return {
  json: {
    output: validationData.message
  }
};

const items = $input.all();
const originalRequest = $('Extract API Config').first().json;
const filterReviewed = originalRequest.filterReviewed;
const filterState = originalRequest.filterState;
const filterDateFrom = originalRequest.filterDateFrom;
const filterDateTo = originalRequest.filterDateTo;

console.log('Filter - filterReviewed:', filterReviewed);
console.log('Filter - filterState:', filterState);
console.log('Filter - filterDateFrom:', filterDateFrom);
console.log('Filter - filterDateTo:', filterDateTo);

// If no filters requested, return all items
if (!filterReviewed && !filterState && !filterDateFrom && !filterDateTo) {
  return items;
}

// Helper function to parse createTs format: "2026-03-19 14:23:41.0"
function parseCreateTs(createTs) {
  if (!createTs) return null;
  // Extract date part: "2026-03-19"
  const datePart = createTs.split(' ')[0];
  return new Date(datePart);
}

// Parse filter dates
const dateFrom = filterDateFrom ? new Date(filterDateFrom) : null;
const dateTo = filterDateTo ? new Date(filterDateTo) : null;

// Process each item
const processedItems = [];

for (const item of items) {
  const data = item.json;

  // Handle array response
  if (Array.isArray(data)) {
    const filtered = data.filter(file => {
      let matchesReviewed = true;
      let matchesState = true;
      let matchesDate = true;

      if (filterReviewed) {
        matchesReviewed = String(file.reviewed) === String(filterReviewed);
      }

      if (filterState) {
        matchesState = file.arrivedFileState === filterState;
      }

      // Date filtering using createTs field
      if (dateFrom || dateTo) {
        const fileDate = parseCreateTs(file.createTs);
        if (fileDate) {
          if (dateFrom && fileDate < dateFrom) {
            matchesDate = false;
          }
          if (dateTo) {
            // Set dateTo to end of day for inclusive comparison
            const dateToEnd = new Date(dateTo);
            dateToEnd.setHours(23, 59, 59, 999);
            if (fileDate > dateToEnd) {
              matchesDate = false;
            }
          }
        } else {
          matchesDate = false; // No createTs, exclude from date filter
        }
      }

      console.log(`File ${file.arrivedFileKey}: state=${file.arrivedFileState}, createTs=${file.createTs}, matches=${matchesReviewed && matchesState && matchesDate}`);
      return matchesReviewed && matchesState && matchesDate;
    });

    // Add filtered array as single item
    if (filtered.length > 0) {
      processedItems.push({ json: filtered });
    }
  } else if (data && typeof data === 'object') {
    // Handle single object
    let matchesReviewed = true;
    let matchesState = true;
    let matchesDate = true;

    if (filterReviewed) {
      matchesReviewed = String(data.reviewed) === String(filterReviewed);
    }

    if (filterState) {
      matchesState = data.arrivedFileState === filterState;
    }

    // Date filtering
    if (dateFrom || dateTo) {
      const fileDate = parseCreateTs(data.createTs);
      if (fileDate) {
        if (dateFrom && fileDate < dateFrom) {
          matchesDate = false;
        }
        if (dateTo) {
          const dateToEnd = new Date(dateTo);
          dateToEnd.setHours(23, 59, 59, 999);
          if (fileDate > dateToEnd) {
            matchesDate = false;
          }
        }
      } else {
        matchesDate = false;
      }
    }

    if (matchesReviewed && matchesState && matchesDate) {
      processedItems.push(item);
    }
  }
}

console.log(`Filter result: ${processedItems.length} items`);
return processedItems.length > 0 ? processedItems : [{ json: [] }];

const items = $input.all();
const originalRequest = $('Extract API Config').first().json;
const filterReviewed = originalRequest.filterReviewed;
const filterState = originalRequest.filterState;

// Combine all items into single response
let allData = [];
items.forEach(item => {
  if (Array.isArray(item.json)) {
    allData = allData.concat(item.json);
  } else {
    allData.push(item.json);
  }
});

const method = originalRequest.method;
const endpoint = originalRequest.endpoint;

let message = '';

// Format based on operation type
if (method === 'GET') {
  // Build filter description
  const filters = [];
  if (filterReviewed === '0') {
    filters.push('unreviewed');
  } else if (filterReviewed === '2') {
    filters.push('reviewed');
  }
  if (filterState) {
    filters.push(`state: ${filterState}`);
  }

  const filterText = filters.length > 0 ? ` (${filters.join(', ')})` : '';

  if (allData.length === 0) {
    message = `🔍 No files found${filterText}.\n\nTry adjusting your search criteria.`;
  } else {
    message = `📋 **Found ${allData.length} file(s)${filterText}:**\n\n`;

    allData.forEach((file, index) => {
      // Status emoji
      let statusEmoji = '❓';
      if (file.arrivedFileState === 'Routed') statusEmoji = '✅';
      else if (file.arrivedFileState === 'Failed') statusEmoji = '❌';
      else if (file.arrivedFileState === 'Routing') statusEmoji = '🔄';

      // Reviewed emoji
      const reviewedEmoji = file.reviewed === 2 ? '✓' : '○';

      message += `**${index + 1}. 📄 ${file.fileName || 'N/A'}**\n`;
      message += `   🔑 Key: \`${file.arrivedFileKey}\`\n`;
      message += `   ${statusEmoji} Status: **${file.arrivedFileState || 'Unknown'}**\n`;
      message += `   ${reviewedEmoji} Reviewed: ${file.reviewed === 2 ? 'Yes' : 'No'}\n`;

      if (file.producerName) {
        message += `   📤 Producer: ${file.producerName}\n`;
      }
      if (file.consumerName) {
        message += `   📥 Consumer: ${file.consumerName}\n`;
      }
      if (file.arrivedTime) {
        const date = new Date(file.arrivedTime);
        const formattedDate = date.toLocaleString('en-US', {
          year: 'numeric',
          month: 'short',
          day: 'numeric',
          hour: '2-digit',
          minute: '2-digit'
        });
        message += `   🕐 Arrived: ${formattedDate}\n`;
      }
      if (file.fileSize) {
        const sizeKB = (file.fileSize / 1024).toFixed(2);
        message += `   💾 Size: ${sizeKB} KB\n`;
      }

      message += `\n`;
    });
  }
} else if (method === 'PUT') {
  const fileKey = endpoint.split('/').pop();
  message = `✅ **Successfully updated file**\n\n`;
  message += `🔑 File Key: \`${fileKey}\`\n`;

  if (originalRequest.body) {
    message += `\n**Changes made:**\n`;
    Object.entries(originalRequest.body).forEach(([key, value]) => {
      if (key === 'reviewed') {
        message += `   ✓ Marked as ${value === 2 ? 'reviewed' : 'unreviewed'}\n`;
      } else {
        message += `   • ${key}: ${value}\n`;
      }
    });
  }
} else if (method === 'POST') {
  if (endpoint.includes('replay')) {
    const fileKey = originalRequest.arrivedFileKey || endpoint.split('/')[2];
    message = `▶️ **Successfully replayed file**\n\n`;
    message += `🔑 File Key: \`${fileKey}\`\n`;
    if (originalRequest.body?.comments) {
      message += `💬 Comments: ${originalRequest.body.comments}\n`;
    }
  } else if (endpoint.includes('redeliver')) {
    const fileKey = originalRequest.arrivedFileKey || endpoint.split('/')[2];
    message = `🔄 **Successfully redelivered file**\n\n`;
    message += `🔑 File Key: \`${fileKey}\`\n`;
    if (originalRequest.body?.consumerName) {
      message += `📥 Consumer: ${originalRequest.body.consumerName}\n`;
    }
    if (originalRequest.body?.comments) {
      message += `💬 Comments: ${originalRequest.body.comments}\n`;
    }
  } else {
    message = `✅ **Operation completed successfully**\n\n`;
    message += `📋 Details: ${JSON.stringify(allData, null, 2)}\n`;
  }
}

return {
  json: {
    output: message
  }
};

const inputData = $input.first().json;
const aiResponse = inputData.choices[0].message.content;

console.log('AI Response:', aiResponse);

let apiConfig;
try {
  let cleanResponse = aiResponse
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  cleanResponse = cleanResponse.replace(/,\s*([}\]])/g, '$1');

  const jsonMatch = cleanResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    apiConfig = JSON.parse(jsonMatch[0]);
  } else {
    apiConfig = JSON.parse(cleanResponse);
  }
} catch (error) {
  return {
    json: {
      validationError: true,
      message: "😊 I'm having trouble understanding that. Let me help you!\n\n**What would you like to do?**\n• View files: 'Show me the files'\n• Update file: 'Update file ABC123 mark as reviewed'\n• Redeliver files: 'Redeliver files ABC123, XYZ789 to consumer Test with comments Batch'\n• Replay files: 'Replay files ABC123, XYZ789 with comments Batch replay'\n\nTry one of these!"
    }
  };
}

console.log('Parsed API Config:', JSON.stringify(apiConfig, null, 2));

if (!apiConfig.method || !apiConfig.endpoint) {
  return {
    json: {
      validationError: true,
      message: "🤔 I'm not sure what you'd like to do. Let me help!\n\n**Choose an action:**\n📋 **View files**: 'Show me all files'\n✏️ **Update**: 'Update file ABC123'\n🔄 **Redeliver**: 'Redeliver files ABC123, XYZ789 to consumer Test with comments Batch'\n▶️ **Replay**: 'Replay files ABC123, XYZ789 with comments Batch replay'\n\nWhat would you like to do?"
    }
  };
}

apiConfig.method = apiConfig.method.toUpperCase();

if (apiConfig.method === 'CONVERSATION') {
  return {
    json: {
      validationError: true,
      message: "🔍 I need more information to help you!\n\n**💡 Tip:** Try these commands:\n• 'Show me all files'\n• 'Update file [arrivedFileKey] mark as reviewed'\n• 'Redeliver files [keys] to consumer XYZ with comments Testing'\n• 'Replay files [keys] with comments Manual replay'\n\nWhat would you like to do?"
    }
  };
}

if (!apiConfig.endpoint.startsWith('/')) {
  apiConfig.endpoint = '/' + apiConfig.endpoint;
}

// Handle multiple arrivedFileKeys for batch operations
if (apiConfig.arrivedFileKeys && Array.isArray(apiConfig.arrivedFileKeys) && apiConfig.arrivedFileKeys.length > 0) {
  // Validate comments for batch replay/redeliver
  if (apiConfig.endpoint.includes('/replayarrivedfile')) {
    if (!apiConfig.body || !apiConfig.body.comments || apiConfig.body.comments.trim() === '') {
      return {
        json: {
          validationError: true,
          message: "💬 **Comments are required for replay!**\n\nPlease provide comments for batch replay.\n\n**Example:**\n'Replay files ABC123, XYZ789 with comments Batch replay due to error'\n\nWhat are your comments?"
        }
      };
    }
  } else if (apiConfig.endpoint.includes('/redeliverarrivedfile')) {
    if (!apiConfig.body || !apiConfig.body.consumerName) {
      return {
        json: {
          validationError: true,
          message: "🔄 To redeliver files, I need:\n1. arrivedFileKeys\n2. Consumer name\n3. Comments\n\n**Example:**\n'Redeliver files ABC123, XYZ789 to consumer Test with comments Batch redeliver'\n\nWhat would you like to do?"
        }
      };
    }
    if (!apiConfig.body.comments || apiConfig.body.comments.trim() === '') {
      return {
        json: {
          validationError: true,
          message: "💬 **Comments are required for redelivery!**\n\nPlease provide comments for batch redelivery.\n\n**Example:**\n'Redeliver files ABC123, XYZ789 to consumer Test with comments Batch redeliver for testing'\n\nWhat are your comments?"
        }
      };
    }
  }

  // Create multiple items, one for each arrivedFileKey
  const items = apiConfig.arrivedFileKeys.map(key => {
    const endpoint = apiConfig.endpoint.replace('/actions/', `/${key}/actions/`);
    return {
      json: {
        method: apiConfig.method,
        endpoint: endpoint,
        body: apiConfig.body,
        queryParams: apiConfig.queryParams || {},
        filterReviewed: apiConfig.filterReviewed,
        filterState: apiConfig.filterState,
        isBatch: true,
        batchCount: apiConfig.arrivedFileKeys.length,
        arrivedFileKey: key
      }
    };
  });

  console.log(`Created ${items.length} batch items`);
  return items;
}

// Validate PUT requires ID
if (apiConfig.method === 'PUT') {
  if (apiConfig.endpoint === '/fgarrivedfiles/' || !apiConfig.endpoint.includes('/fgarrivedfiles/')) {
    return {
      json: {
        validationError: true,
        message: "🔍 To update a file, I need the arrivedFileKey!\n\n**💡 Tip:** If you don't know the arrivedFileKey, list files first:\n• 'Show me all files'\n\n**Then provide the arrivedFileKey:**\n• 'Update file ABC123 mark as reviewed'\n\nWhat would you like to do?"
      }
    };
  }
  if (!apiConfig.body || typeof apiConfig.body !== 'object' || Object.keys(apiConfig.body).length === 0) {
    return {
      json: {
        validationError: true,
        message: "✏️ To update a file, **tell me what you want to change**.\n\n**Example:**\n'Update file ABC123: mark as reviewed, reviewed to 2'\n\nWhat would you like to update?"
      }
    };
  }
}

// Validate POST operations (single file)
if (apiConfig.method === 'POST') {
  if (apiConfig.endpoint.includes('/redeliverarrivedfile')) {
    if (!apiConfig.body || !apiConfig.body.consumerName) {
      return {
        json: {
          validationError: true,
          message: "🔄 To redeliver a file, I need:\n1. arrivedFileKey\n2. Consumer name\n3. Comments\n\n**Example:**\n'Redeliver file ABC123 to consumer TestConsumer with comments Redelivering for testing'\n\nWhat would you like to do?"
        }
      };
    }
    if (!apiConfig.body.comments || apiConfig.body.comments.trim() === '') {
      return {
        json: {
          validationError: true,
          message: "💬 **Comments are required for redelivery!**\n\nPlease provide comments explaining why you're redelivering this file.\n\n**Example:**\n'Redeliver file ABC123 to consumer TestConsumer with comments Redelivering due to processing error'\n\nWhat are your comments?"
        }
      };
    }
  } else if (apiConfig.endpoint.includes('/replayarrivedfile')) {
    if (apiConfig.endpoint === '/fgarrivedfiles/actions/replayarrivedfile' || !apiConfig.endpoint.match(/\/fgarrivedfiles\/[^\/]+\/actions\/replayarrivedfile/)) {
      return {
        json: {
          validationError: true,
          message: "▶️ To replay a file, I need:\n1. arrivedFileKey\n2. Comments\n\n**Example:**\n'Replay file ABC123 with comments Manual replay due to error'\n\nWhat would you like to do?"
        }
      };
    }
    if (!apiConfig.body || !apiConfig.body.comments || apiConfig.body.comments.trim() === '') {
      return {
        json: {
          validationError: true,
          message: "💬 **Comments are required for replay!**\n\nPlease provide comments explaining why you're replaying this file.\n\n**Example:**\n'Replay file ABC123 with comments Replaying due to processing failure'\n\nWhat are your comments?"
        }
      };
    }
  }
}

if (apiConfig.method === 'GET') {
  apiConfig.body = null;
}

if (!apiConfig.queryParams || typeof apiConfig.queryParams !== 'object') {
  apiConfig.queryParams = {};
} else {
  const cleanedParams = {};
  for (const [key, value] of Object.entries(apiConfig.queryParams)) {
    if (key && key.trim() !== '') {
      cleanedParams[key] = value;
    }
  }
  apiConfig.queryParams = cleanedParams;
}

console.log('Final API Config:', JSON.stringify(apiConfig, null, 2));

return {
  json: apiConfig
};

const userMessage = $input.first().json.userMessage;

const requestBody = {
  model: "gpt-3.5-turbo",
  temperature: 0,
  max_tokens: 800,
  messages: [
    {
      role: "system",
      content: "Convert File Gateway requests to JSON. Respond ONLY with valid JSON, no explanations.

CRITICAL RULES:
- ID is the arrivedFileKey field (string key), NOT the fileName
- fileName is ONLY for searching in queryParams
- For update/redeliver/replay: use arrivedFileKey in endpoint, NOT fileName
- MULTIPLE FILES: If multiple arrivedFileKeys provided, put them in arrivedFileKeys array
- Extract ONLY values explicitly mentioned
- Missing fields = null
- For search: use queryParams
- Default endpoint: /fgarrivedfiles/
- Redeliver REQUIRES: arrivedFileKey(s), consumerName, comments
- Replay REQUIRES: arrivedFileKey(s), comments
- Reviewed field: When user says 'mark as reviewed' or 'set reviewed', automatically set reviewed: 2 in body
- Reviewed field values: 0=not reviewed, 2=reviewed (system-generated)
- If user asks for unreviewed/not reviewed files, add filterReviewed: '0' to response
- If user asks for reviewed files, add filterReviewed: '2' to response
- arrivedFileState field values: Routed, Failed, Routing (case-sensitive, exact match required)
- CRITICAL: When user says 'error', 'failed', 'failure', 'fail' → use filterState: 'Failed' (capital F)
- If user asks for files with state/status routed, add filterState: 'Routed'
- If user asks for files with state/status routing, add filterState: 'Routing'
- IMPORTANT: User terms 'error'/'failed'/'failure' ALL map to API value 'Failed'
- DATE FILTERING: Extract dates from user queries and add filterDateFrom and/or filterDateTo
- Date format: YYYY-MM-DD (e.g., 2024-01-15)
- Recognize: 'between X and Y', 'from X to Y', 'after X', 'before Y', 'on X', 'today', 'yesterday'
- 'today' = current date, 'yesterday' = previous date

Format: {"method":"GET|POST|PUT","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{},"filterReviewed":null,"filterState":null,"filterDateFrom":null,"filterDateTo":null,"arrivedFileKeys":null}

GET: body=null, queryParams for filters, filterReviewed for client-side filtering (0 or 2), filterState for client-side state filtering (Routed, Failed, Routing), filterDateFrom/filterDateTo for date range filtering
PUT: endpoint=/fgarrivedfiles/{arrivedFileKey}, body={ONLY fields to change, reviewed:2 if marking as reviewed}
POST redeliver: endpoint=/fgarrivedfiles/{arrivedFileKey}/actions/redeliverarrivedfile, body={"consumerName":"name","comments":"text"}, arrivedFileKeys=[keys] for multiple
POST replay: endpoint=/fgarrivedfiles/{arrivedFileKey}/actions/replayarrivedfile, body={"comments":"text"}, arrivedFileKeys=[keys] for multiple

Examples:

'get all files' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"10"},"filterReviewed":null,"filterState":null,"filterDateFrom":null,"filterDateTo":null,"arrivedFileKeys":null}

'show files received today' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"50"},"filterReviewed":null,"filterState":null,"filterDateFrom":"2026-03-19","filterDateTo":"2026-03-19","arrivedFileKeys":null}

'get files between 2024-01-01 and 2024-01-31' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"100"},"filterReviewed":null,"filterState":null,"filterDateFrom":"2024-01-01","filterDateTo":"2024-01-31","arrivedFileKeys":null}

'show failed files from last week' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"50"},"filterReviewed":null,"filterState":"Failed","filterDateFrom":"2026-03-12","filterDateTo":"2026-03-19","arrivedFileKeys":null}

'get files after 2024-03-01' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"50"},"filterReviewed":null,"filterState":null,"filterDateFrom":"2024-03-01","filterDateTo":null,"arrivedFileKeys":null}

'show me unreviewed files' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"50"},"filterReviewed":"0","filterState":null,"filterDateFrom":null,"filterDateTo":null,"arrivedFileKeys":null}

'get files with status error' -> {"method":"GET","endpoint":"/fgarrivedfiles/","body":null,"queryParams":{"limit":"50"},"filterReviewed":null,"filterState":"Failed","filterDateFrom":null,"filterDateTo":null,"arrivedFileKeys":null}

'mark file ABC123 as reviewed' -> {"method":"PUT","endpoint":"/fgarrivedfiles/ABC123","body":{"reviewed":2},"queryParams":{},"filterReviewed":null,"filterState":null,"filterDateFrom":null,"filterDateTo":null,"arrivedFileKeys":null}

'replay files ABC123, XYZ789 with comments AgentReplay' -> {"method":"POST","endpoint":"/fgarrivedfiles/actions/replayarrivedfile","body":{"comments":"AgentReplay"},"queryParams":{},"filterReviewed":null,"filterState":null,"filterDateFrom":null,"filterDateTo":null,"arrivedFileKeys":["ABC123","XYZ789"]}"
    },
    {
      role: "user",
      content: userMessage
    }
  ]
};

return {
  json: requestBody
};

const inputData = $input.first().json;
const aiResponse = inputData.choices[0].message.content;

return {
  json: {
    output: aiResponse
  }
};

const inputData = $input.first().json;
const aiResponse = inputData.choices[0].message.content;

let intent;
try {
  const cleanResponse = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  intent = JSON.parse(cleanResponse);
} catch (error) {
  intent = { intent: "conversation", reason: "Parse error" };
}

const userMessage = $('When chat message received').first().json.chatInput;

return {
  json: {
    intent: intent.intent,
    reason: intent.reason,
    userMessage: userMessage
  }
};

const userMessage = $input.first().json.chatInput;

const requestBody = {
  model: "gpt-3.5-turbo",
  temperature: 0,
  max_tokens: 150,
  messages: [
    {
      role: "system",
      content: "Classify user intent. Respond with ONLY a JSON object:\n{\"intent\":\"conversation|api_call\",\"reason\":\"brief explanation\"}\n\nIntent types:\n- conversation: Questions about capabilities, help, how-to, examples, greetings\n- api_call: Actual requests to perform operations with specific data (get files, update file X, redeliver file Y, replay file Z)\n\nExamples:\nUser: 'What can you help with?' -> {\"intent\":\"conversation\",\"reason\":\"Help question\"}\nUser: 'Show me files' -> {\"intent\":\"api_call\",\"reason\":\"Get files request\"}\nUser: 'Update file ABC123' -> {\"intent\":\"api_call\",\"reason\":\"Update request\"}\nUser: 'Hello' -> {\"intent\":\"conversation\",\"reason\":\"Greeting\"}"
    },
    {
      role: "user",
      content: `Classify: ${userMessage}`
    }
  ]
};

return {
  json: requestBody
};
